module top_module(
	input Clock,
	input [31:0] saidaALU, dataMEM,
	input [4:0] registradorDestinoData,
	input [1:0] WB,
	output reg [31:0]	saidaALUwb, saidaMEM,
	output reg [4:0] saidaDestinoData,
	output reg [1:0] regWB
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge Clock or posedge dbg_halt) begin

	saidaALUwb <= saidaALU;
	saidaMEM <= dataMEM;
	saidaDestinoData <= registradorDestinoData;
	regWB <= WB;

 end

endmodule
